package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    void testParseReturnsCSVParserInstance() throws Exception {
        // Use reflection to create a mock CSVParser and intercept constructor call
        CSVFormat format = CSVFormat.DEFAULT;

        // Create a mock CSVParser instance
        CSVParser mockParser = mock(CSVParser.class);

        // Use reflection to replace CSVParser constructor call in CSVFormat.parse
        // Since we cannot mock constructor directly with Mockito 3, 
        // we simulate by subclassing CSVFormat with overridden parse method for test

        CSVFormat formatSpy = new CSVFormat(format.getDelimiter(),
                format.getQuoteCharacter(),
                format.getQuoteMode(),
                format.getCommentMarker(),
                format.getEscapeCharacter(),
                format.getIgnoreSurroundingSpaces(),
                format.getIgnoreEmptyLines(),
                format.getRecordSeparator(),
                format.getNullString(),
                format.getHeaderComments(),
                format.getHeader(),
                format.getSkipHeaderRecord(),
                format.getAllowMissingColumnNames(),
                format.getIgnoreHeaderCase()) {
            @Override
            public CSVParser parse(final Reader in) throws IOException {
                // Return the mocked parser instead of real one
                return mockParser;
            }
        };

        CSVParser parser = formatSpy.parse(mockReader);

        assertNotNull(parser);
        assertSame(mockParser, parser);
    }

    @Test
    void testParseWithNullReaderThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertThrows(NullPointerException.class, () -> format.parse(null));
    }
}
